GUISubAnimMove = class("GUISubAnimMove", GUISubAnim)

local function addTable(tb1, tb2)
    local metatable = {
        __add = function(tb1, tb2)
            local result = {
                tb1[1] + tb2[1],
                tb1[2] + tb2[2],
                tb1[3] + tb2[3],
                tb1[4] + tb2[4],
            }
            return result
    end
    }

    setmetatable(tb1, metatable)
    setmetatable(tb2, metatable)

    return tb1 + tb2
end

local function subTable(tb1, tb2)
    local metatable = {
        __sub = function(tb1, tb2)
            local result = {
                tb1[1] - tb2[1],
                tb1[2] - tb2[2],
                tb1[3] - tb2[3],
                tb1[4] - tb2[4],
            }
            return result
        end
    }

    setmetatable(tb1, metatable)
    setmetatable(tb2, metatable)

    return tb1 - tb2
end

local function divTable(tb, v)
    local metatable = {
        __div = function(tb, v)
            local result = {
                (tb[1] / v),
                (tb[2] / v),
                (tb[3] / v),
                (tb[4] / v),
            }
            return result
        end
    }

    setmetatable(tb, metatable)

    return (tb / v)
end

function GUISubAnimMove:play()
    self.moveStart = StringUtil.split(self.config.moveStart, ",", false, true)
    self.moveEnd = StringUtil.split(self.config.moveEnd, ",", false, true)
    self.move = self.moveStart
    self.delta = divTable(subTable(self.moveEnd, self.moveStart), self.ticks)
    self.tick = 1
    LogUtil.log("GUISubAnimMove:play " .. inspect.inspect(self.delta))
end

function GUISubAnimMove:update()
    if self.isEnd then
        return
    end

    self.move = addTable(self.move, self.delta)
    self.window:SetXPosition({ self.move[1], self.move[3] })
    self.window:SetYPosition({ self.move[2], self.move[4] })
    LogUtil.log(string.format("GUISubAnimMove:update tick:%d { %d %d %d %d }",
            self.tick, self.move[1], self.move[2], self.move[3], self.move[4]))

    if self.tick == self.ticks then
        self.window:SetXPosition({ self.moveEnd[1], self.moveEnd[3] })
        self.window:SetYPosition({ self.moveEnd[2], self.moveEnd[4] })
        self.isEnd = true
    end

    self.tick = self.tick + 1
end

